// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{})
}

// ServeMux is an abstraction of [http.ServeMux].
type ServeMux interface {
	HandleFunc(pattern string, handler func(http.ResponseWriter, *http.Request))
	http.Handler
}

type StdHTTPServerOptions struct {
	BaseURL          string
	BaseRouter       ServeMux
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, m ServeMux) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseRouter: m,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, m ServeMux, baseURL string) http.Handler {
	return HandlerWithOptions(si, StdHTTPServerOptions{
		BaseURL:    baseURL,
		BaseRouter: m,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options StdHTTPServerOptions) http.Handler {
	m := options.BaseRouter

	if m == nil {
		m = http.NewServeMux()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/healthz", wrapper.Health)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/openapi.yaml", wrapper.GetOpenAPI)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/capabilities", wrapper.GetCapabilities)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/uploads/documents", wrapper.UploadDocument)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/uploads/collections", wrapper.UploadCollection)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/uploads/inspect", wrapper.InspectUpload)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/uploads/get", wrapper.GetUpload)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/uploads/delete", wrapper.DeleteUpload)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/uploads", wrapper.ListManifestUploads)
	m.HandleFunc(http.MethodGet+" "+options.BaseURL+"/api/v1/storage/uploads", wrapper.ListStorageUploads)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/sync", wrapper.SyncManifest)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/purge/preview", wrapper.PreviewPurge)
	m.HandleFunc(http.MethodPost+" "+options.BaseURL+"/api/v1/purge", wrapper.ExecutePurge)

	return m
}

